import { cn } from '@/utils/cn';
import { type ComponentProps, type JSX } from 'solid-js';

/**
 * Props for the CardBody component
 */
interface CardBodyProps extends ComponentProps<'div'> {
	/** Body content */
	children?: JSX.Element;
	/** Padding variant for different content types */
	padding?: 'none' | 'sm' | 'md' | 'lg';
	spacing?: 'none' | 'sm' | 'md' | 'lg';
}

/**
 * CardBody component - Main content area for cards
 *
 * Features:
 * - Flexible content container
 * - Configurable padding options
 * - Proper spacing and typography
 * - Uses design system colors
 *
 * @example
 * ```tsx
 * <CardBody padding="lg">
 *   <p>Main card content goes here</p>
 * </CardBody>
 * ```
 */
export default function CardBody(props: CardBodyProps): JSX.Element {
	const { children, padding = 'md', class: className, ...bodyProps } = props;

	const getPaddingClasses = () => {
		switch (padding) {
			case 'none':
				return '';
			case 'sm':
				return 'px-4 py-3';
			case 'lg':
				return 'px-8 py-6';
			case 'md':
			default:
				return 'px-6 py-4';
		}
	};

	return (
		<div class={cn(getPaddingClasses(), className)} {...bodyProps}>
			{children}
		</div>
	);
}
